import { createSlice } from "@reduxjs/toolkit";
import { configureStore } from "@reduxjs/toolkit";

const initialState={
    user:[{id:1,name:'abir'}],
    train:[

    {id:1,name:'Parabot Express',stations:['Sylhet','Maijgaon','Bhairab','Dhaka'],total_seat:30,boookd_ticket:[]},
    {id:2,name:'Dhumketu Express',stations:['Dhaka','Bimanbandar','Bangabondhu East','M Monsur Ali','Boral Bridge','Ishwardi Bypass','Abdullahpur'],total_seat:30,boookd_ticket:[]},
    {id:3,name:'Silkcity Express',stations:['Dhaka','Bimanbandar','Bangabondhu East','M Monsur Ali','Boral Bridge','Ishwardi Bypass','Abdullahpur'],total_seat:30,boookd_ticket:[]},
    {id:4,name:'Sonargaon Express',stations:['Sylhet','Maijgaon','Bhairab','Dhaka'],total_seat:30,boookd_ticket:[]},
    {id:5,name:'Banalata Express',stations:['Dhaka','Bimanbandar','Bangabondhu East','M Monsur Ali','Boral Bridge','Ishwardi Bypass','Abdullahpur','Jessore','Benapole'],total_seat:30,boookd_ticket:[]},
    {id:6,name:'Rangpur Express',stations:['Sylhet','Maijgaon','Bhairab','Dhaka'],total_seat:30,boookd_ticket:[]},
    {id:7,name:'Chilahati Express',stations:['Dhaka','Bimanbandar','Bangabondhu East','M Monsur Ali','Boral Bridge','Ishwardi Bypass','Abdullahpur'],total_seat:30,boookd_ticket:[]},
    {id:8,name:'Ekota Express',stations:['Dhaka','Bimanbandar','Bangabondhu East','M Monsur Ali','Boral Bridge','Ishwardi Bypass','Abdullahpur'],total_seat:30,boookd_ticket:[]},
    {id:9,name:'Upobon Express',stations:['Sylhet','Maijgaon','Bhairab','Dhaka'],total_seat:30,boookd_ticket:[]},
    {id:10,name:'Joyontika Express',stations:['Sylhet','Maijgaon','Bhairab','Dhaka'],total_seat:30,boookd_ticket:[]},
    {id:11,name:'Kalni Express',stations:['Sylhet','Maijgaon','Bhairab','Sreemangal','Dhaka'],total_seat:30,boookd_ticket:[]},
    {id:12,name:'Parabot Express',stations:['Sylhet','Maijgaon','Bhairab','Dhaka'],total_seat:30,boookd_ticket:[]}],
    journey_inf:[]



};

const variable=
{   
    name:'variable',
    initialState,
    reducers:{
        addItem:(state,action)=>{
            const item={
                id:'2',
                name:action.payload
            }
            state.user.push(item)
        },
        addDetails:(state,action)=>{
            state.journey_inf.push(action.payload)
        }

    }
}



const variableSlice=createSlice(variable)

export const {addItem,addDetails}=variableSlice.actions


// export default variableSlice.reducer
export const store=configureStore({
    reducer:{
        var:variableSlice.reducer,
    }
})
